class Solution:
    def find132pattern(self, nums):
        n = len(nums)
        if n < 3:
            return False
        min_left = nums[0]
        for j in range(1, n - 1):
            for k in range(j + 1, n):
                if min_left < nums[k] < nums[j]:
                    return True
            min_left = min(min_left, nums[j])
        return False

